import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as l,c as p,e as t,a as e,b as n,d as r,f as o}from"./app-e3a32e99.js";const c="/assets/img/inference_learning/image-20260422175336222.png",d="/assets/img/inference_learning/image-20260424181111992.png",h="/assets/img/inference_learning/image-20260430191405923.png",m={},u=e("p",null,"对部分 test-time compute / inference-time learning / reasoning models 的记录。",-1),v=e("hr",null,null,-1),g=e("h2",{id:"openai-o1",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#openai-o1","aria-hidden":"true"},"#"),n(" OpenAI O1")],-1),b={href:"https://openai.com/zh-Hans-CN/index/learning-to-reason-with-llms/",target:"_blank",rel:"noopener noreferrer"},f=o('<blockquote><p>这里发现，随着强化学习（训练时间计算）和思考时间（测试时间计算）的增加，o1 的性能也在不断提高。这种方法的扩展限制与 LLM 预训练的限制有很大不同，这里正在继续研究。</p></blockquote><figure><img src="'+c+`" alt="image-20260422175336222" tabindex="0" loading="lazy"><figcaption>image-20260422175336222</figcaption></figure><hr><h2 id="deepseek-r1-zero" tabindex="-1"><a class="header-anchor" href="#deepseek-r1-zero" aria-hidden="true">#</a> DeepSeek-R1-Zero</h2><p>在 DeepSeek-R1 论文中，aha moment 并不是由单个现象证明的，而是由一组证据共同构成的。论文中可以看到几个关键趋势：</p><ul><li>首先，模型在 RL 训练过程中 accuracy 明显上升，说明纯 RL 确实提升了模型在复杂推理任务上的表现。</li><li>其次，average response length 也随着训练增加。论文将其解释为模型学会使用更多 thinking time，也就是在回答前进行更长的搜索、验证和推导。</li><li>第三，论文还统计了 reflective words，例如 “wait”“check”“verify”“mistake”“wrong” 等词的频率。尤其是 “wait” 这个词，在训练后期出现了明显 spike。再结合论文中的具体样例，模型在中途说出 “Wait, wait…” 并重新评估自己的解题步骤，作者将这种行为称为 aha moment。</li></ul><p>因此，DeepSeek-R1 论文中的 aha moment 更像是一种训练后期出现的推理行为变化：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">短回答 / 普通推理</span></span>
<span class="line"><span style="color:#24292e;">→ 更长 reasoning</span></span>
<span class="line"><span style="color:#24292e;">→ 自我检查</span></span>
<span class="line"><span style="color:#24292e;">→ 发现可能的问题</span></span>
<span class="line"><span style="color:#24292e;">→ 重新评估</span></span>
<span class="line"><span style="color:#24292e;">→ 修正推理路径</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>也就是说，论文中的 aha moment 不是简单地说模型出现了某个词，而是模型在 RL 过程中学会了更长、更反思式的推理策略。</p><figure><img src="`+d+`" alt="image-20260424181111992" tabindex="0" loading="lazy"><figcaption>image-20260424181111992</figcaption></figure><hr><h3 id="aha-moment-复现结果" tabindex="-1"><a class="header-anchor" href="#aha-moment-复现结果" aria-hidden="true">#</a> Aha Moment 复现结果</h3><h4 id="_1-总结-这里到底有没有观察到-aha-moment" tabindex="-1"><a class="header-anchor" href="#_1-总结-这里到底有没有观察到-aha-moment" aria-hidden="true">#</a> 1. 总结：这里到底有没有观察到 “Aha Moment”？</h4><p>用 3B 和 7B 模型分别在 countdown 任务上进行 GRPO/PPO，尝试观察 <strong>aha moment</strong></p><p>分析了训练过程中部分保存下来的 595 条 response，覆盖 step 1 到 step 139。统计了正确率、response 长度和反思词频率，也进一步观察了不同训练阶段的具体样例，尝试区分“表面反思”和“真正有效的自我修正”。</p><p>最终，结论是：</p><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>这次实验确实观察到了 RL 让模型解题能力提升，也观察到了模型推理策略的变化；但它并没有明显复现 DeepSeek-R1 论文中那种典型的 “response length 增长 + wait 频率爆发 + 长链自我反思” 的 aha moment。 相反，这里看到的是另一种更适合 countdown 任务的策略迁移：模型从早期的长篇混乱试错，逐渐转向更短、更直接、更高效的表达式搜索。</p><h4 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a> :::</h4><hr><h4 id="_2-countdown-实验观察到了什么" tabindex="-1"><a class="header-anchor" href="#_2-countdown-实验观察到了什么" aria-hidden="true">#</a> 2. countdown 实验观察到了什么？</h4><p>实验也观察到了明显的能力提升。从整体趋势看，模型正确率随着训练上升：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">step 1–30:   8.6%</span></span>
<span class="line"><span style="color:#24292e;">step 31–70:  53.7%</span></span>
<span class="line"><span style="color:#24292e;">step 71–110: 64.1%</span></span>
<span class="line"><span style="color:#24292e;">step 111–139: 68.0%</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这说明 RL 训练确实让模型更会做 countdown 任务。</p><p>但是， <strong>和 DeepSeek-R1 论文不同的是， response length 并没有随着训练增加，反而呈下降趋势。</strong> 早期模型经常输出很长的思维过程，但这些长 reasoning 大多是无效试错；后期模型的输出更短，却更容易正确。</p><p>更有意思的是，“wait” 这类反思词在实验中并不是后期出现，而是早期更多。早期模型经常说 “let me check”“try another approach”“this doesn’t work”， <strong>但最后仍然得不到正确答案</strong> 。到了后期，这些反思语言反而减少，模型更多时候直接给出简洁的表达式。</p><p>这说明：</p><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>在 countdown 实验里，反思词并不是 aha moment 的可靠信号。 很多时候，反思语言只是模型失败搜索时的表面语言，而不代表真正的有效修正。</p></div></div><hr><h4 id="_3-从具体-response-中看到的阶段变化" tabindex="-1"><a class="header-anchor" href="#_3-从具体-response-中看到的阶段变化" aria-hidden="true">#</a> 3. 从具体 response 中看到的阶段变化</h4><p>通过每个阶段挑选代表性 response，这里可以更清楚地看到模型策略的变化。</p><p>在早期阶段，模型虽然会尝试很多方法，也会使用 “check”“try again” 之类的语言，但它经常违反任务规则，例如引入没有给定的数字，或者最后表达式并不等于 target。这个阶段的模型看起来“想了很多”，但实际上缺少有效约束。</p><p>到了中期，模型开始出现更有序的枚举行为。它会尝试多个候选表达式，并检查它们是否等于 target。虽然这种方式仍然比较笨拙，但已经比早期的随机试错稳定很多。</p><p>再往后，模型的枚举过程变得更加规范。它开始更频繁地明确比较候选表达式和目标值，比如 “this does not equal 29”。这说明模型学会了一个重要模式：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">生成候选表达式</span></span>
<span class="line"><span style="color:#24292e;">→ 计算结果</span></span>
<span class="line"><span style="color:#24292e;">→ 和 target 对比</span></span>
<span class="line"><span style="color:#24292e;">→ 不对就继续搜索</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>到了最后阶段，模型经常能直接找到短表达式。例如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">45 + 97 - 90 = 52</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这类 response 很短，但正确、合法、格式稳定。</p><p>因此，四个阶段整体呈现出这样一条路径：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">长篇混乱试错</span></span>
<span class="line"><span style="color:#24292e;">→ 有序枚举</span></span>
<span class="line"><span style="color:#24292e;">→ target check</span></span>
<span class="line"><span style="color:#24292e;">→ 短表达式直接搜索</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这是一种清晰的策略进步，但它并不是 DeepSeek-R1 论文中那种典型的长链反思式 aha moment。</p><hr><h4 id="_4-为什么结果和-deepseek-r1-不一样" tabindex="-1"><a class="header-anchor" href="#_4-为什么结果和-deepseek-r1-不一样" aria-hidden="true">#</a> 4. 为什么结果和 DeepSeek-R1 不一样？</h4><p>最重要的原因可能是： <strong>任务不同，最优策略也不同。</strong></p><p>DeepSeek-R1 面对的是复杂数学、代码等高难度 reasoning tasks。这类任务往往需要多步推导、条件检查、反向思考和错误修正。对于这样的任务，写更长的 reasoning、进行更多 self-reflection，可能真的能提高 reward。</p><p>但 countdown 任务不一样。它本质上是一个小型表达式搜索问题。很多题可以通过较短的结构解决，例如：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">a + b - c</span></span>
<span class="line"><span style="color:#24292e;">a - b + c</span></span>
<span class="line"><span style="color:#24292e;">a * b - c</span></span>
<span class="line"><span style="color:#24292e;">(a + b) / c</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这种任务中，过长的 reasoning 不一定有帮助，反而可能导致模型陷入错误循环、重复数字、引入非法数字，或者格式失败。</p><p>所以，RL 在实验中没有鼓励模型“想得更长”，而是鼓励模型“搜得更准、更快、更短”。</p><p>这也解释了为什么实验中会出现：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">accuracy 上升</span></span>
<span class="line"><span style="color:#24292e;">response length 下降</span></span>
<span class="line"><span style="color:#24292e;">wait 频率下降</span></span>
<span class="line"><span style="color:#24292e;">direct solve / enumerative search 上升</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这并不是训练失败，而是说明模型学到了一种更适合 countdown 任务的策略。</p><hr><h4 id="_5-一个统一解释-奖励诱导的推理策略迁移" tabindex="-1"><a class="header-anchor" href="#_5-一个统一解释-奖励诱导的推理策略迁移" aria-hidden="true">#</a> 5. 一个统一解释：奖励诱导的推理策略迁移</h4><p>为了同时解释 DeepSeek-R1 论文和实验结果，这里提出一个更大的理解框架：</p><blockquote><p><strong>Reward-Induced Reasoning Policy Shift</strong> 奖励诱导的推理策略迁移。</p></blockquote><p>这个框架认为，RL 并不会固定地产生某一种推理行为。它不会必然让模型输出更长，也不会必然让模型说 “wait”。RL 真正做的是：在给定任务、reward 设计、base model prior 和训练约束下，推动模型寻找更容易获得 reward 的推理策略。</p><p>换句话说，模型在 RL 中学习的是：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">面对这个任务，我应该如何分配我的 token？</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>对于复杂数学任务，最优策略可能是：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">多推导</span></span>
<span class="line"><span style="color:#24292e;">多检查</span></span>
<span class="line"><span style="color:#24292e;">多反思</span></span>
<span class="line"><span style="color:#24292e;">必要时重新开始</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>于是这里看到 DeepSeek-R1 中的 response length 增加和 wait spike。</p><p>而对于 countdown 任务，最优策略可能是：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">快速生成合法表达式</span></span>
<span class="line"><span style="color:#24292e;">检查是否等于 target</span></span>
<span class="line"><span style="color:#24292e;">找到答案后立即停止</span></span>
<span class="line"><span style="color:#24292e;">减少无效解释</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>于是这里看到本次实验中的 response length 下降和搜索效率提升。</p><p>因此，DeepSeek-R1 的 aha moment 和这里实验中的搜索效率提升并不是矛盾的。它们可以被看作同一个机制在不同任务环境下的两种表现。</p><hr><h4 id="_6-这里对-aha-moment-的重新理解" tabindex="-1"><a class="header-anchor" href="#_6-这里对-aha-moment-的重新理解" aria-hidden="true">#</a> 6. 这里对 “aha moment” 的重新理解</h4><p>经过这次实验，我认为不能把 aha moment 简单理解为：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">模型说了 wait</span></span>
<span class="line"><span style="color:#24292e;">模型输出变长</span></span>
<span class="line"><span style="color:#24292e;">模型用了反思词</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这些只是表面信号，更合理的定义应该是：</p><blockquote><p><strong>Aha moment 是 RL 训练过程中，模型解题策略发生可观察的阶段性重组。</strong></p></blockquote><p>在 DeepSeek-R1 中，这种重组表现为：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">更长 reasoning</span></span>
<span class="line"><span style="color:#24292e;">更多 self-reflection</span></span>
<span class="line"><span style="color:#24292e;">更多重新评估</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>而在 countdown 实验中，这种重组表现为：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">更少无效反思</span></span>
<span class="line"><span style="color:#24292e;">更稳定的候选搜索</span></span>
<span class="line"><span style="color:#24292e;">更明确的 target check</span></span>
<span class="line"><span style="color:#24292e;">更短、更直接的正确表达式</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>因此，aha moment 不一定总是“想得更长”。在某些任务中，它也可能表现为“想得更短、更准”。</p><hr><p>这次实验最重要的发现不是“这里复现了 DeepSeek-R1 的 aha moment”，而是：</p><blockquote><p><strong>这里观察到了另一种 RL 诱导的推理策略迁移。</strong></p></blockquote><p>DeepSeek-R1 论文中的 aha moment 表现为模型在复杂任务中扩展 thinking time，学会更长的反思式推理。</p><p>而 countdown 实验则显示，在较简单、可验证、搜索空间有限的任务中，RL 可能会推动模型压缩无效 reasoning，形成更短、更稳定、更高效的表达式搜索策略。</p><div class="hint-container info"><p class="hint-container-title">相关信息</p><p>Aha moment 或许不应该被狭义地理解为 “wait” 的出现或 response length 的增长。 更本质地说，它是 RL 奖励压力下模型推理策略的重组。 在不同任务中，这种重组会呈现出不同形态：有时是长链反思，有时是高效搜索。</p></div><hr><h2 id="minimax-m1" tabindex="-1"><a class="header-anchor" href="#minimax-m1" aria-hidden="true">#</a> Minimax-M1</h2><p>RL 训练时候的一些指标。该结论与 DeepSeek-R1-Zero 类似，仅用 RL 就把 “inference-time thinking length” 提高了。</p><p>这三类都属于更偏 <strong>可验证任务</strong> 的 benchmark，所以它们反映出来的增长， <strong>很大程度上确实是在观察 rule-based / verifiable reasoning 能力的提升</strong> 。但从论文上下文看，图片本身不太像是在严格声明“这里只分析 rule-based RL 阶段”，可能有包括了 GenRL。</p><figure><img src="`+h+'" alt="image-20260430191405923" tabindex="0" loading="lazy"><figcaption>image-20260430191405923</figcaption></figure><p>后续的 M2，M2.7 相关模型都针对 RL 部分进行了更多的处理，让 Minimax 模型在 agent coding 任务上表现更佳。</p><hr><h2 id="trading-inference-time-compute-for-adversarial-robustness" tabindex="-1"><a class="header-anchor" href="#trading-inference-time-compute-for-adversarial-robustness" aria-hidden="true">#</a> Trading Inference-Time Compute for Adversarial Robustness</h2><p>待续</p>',81);function y(x,k){const s=i("ExternalLinkIcon");return l(),p("div",null,[u,t("more"),v,g,e("p",null,[n("在 "),e("a",b,[n("openai 官方"),r(s)]),n("发布中提到：")]),f])}const w=a(m,[["render",y],["__file","笔记inference_learning.html.vue"]]);export{w as default};
